INSERT INTO `faqs` (`id`, `question`, `answer`, `category_id`, `view_count`, `created_at`, `updated_at`) VALUES
(1, 'How do I connect to the company Wi-Fi?', 'Go to Settings > Wi-Fi > Select \"CompanyWiFi\" > Enter your domain credentials (username and password)', 1, 45, '2025-09-10 09:31:34', '2025-09-10 09:31:34'),
(2, 'How do I reset my password?', 'Contact your system administrator through the helpdesk portal or call the IT support line at ext. 1234', 4, 67, '2025-09-10 09:31:34', '2025-09-10 09:31:34'),
(3, 'What should I do if my computer won\'t start?', 'Check power cable connection, try a different power outlet, ensure power button is pressed firmly. If issue persists, contact IT support.', 2, 23, '2025-09-10 09:31:34', '2025-09-10 09:31:34'),
(4, 'How do I install new software?', 'Submit a software installation request ticket through the portal. Admin approval may be required for licensed software.', 3, 34, '2025-09-10 09:31:34', '2025-09-10 09:31:34'),
(5, 'How do I access company VPN?', 'Download the company VPN client from the IT portal, use your domain credentials to connect. Contact IT if you need the installation file.', 1, 56, '2025-09-10 09:31:34', '2025-09-10 09:31:34');
