(13, 'Auto Refresh not working, need relogin to check updated data r comments', 39, '2025-11-21 05:54:14', 'not-resolved', NULL),
(14, 'A ticket Status can be changed from Open to Closed only when a comment is entered by the agent. without a comment, it should not close.', 50, '2025-11-21 06:27:12', 'resolved', 'uploads/bug_1763706432_692006403f52f.png'),
(15, 'The ‘Send Comment’ button should be renamed to ‘Save Comment’, and the ‘Change Ticket Status’ option should appear beside the ‘Save Comment’ button.”', 50, '2025-11-25 04:24:04', 'not-resolved', 'uploads/bug_1764044644_69252f643b1cb.png'),
(16, 'The \"Other\" option is required in the category and subcategory.', 50, '2025-11-27 11:22:54', 'not-resolved', 'uploads/bug_1764242574_6928348e11548.png'),
(17, 'Forgot password option not working.', 50, '2026-01-05 05:50:23', 'not-resolved', 'uploads/bug_1767592223_695b511f4c931.png');
